import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { ThemeProvider, createTheme, CssBaseline } from '@mui/material';
import { AuthProvider } from './context/AuthContext';
import Dashboard from './pages/Dashboard';
import Business from './pages/Business';
import BestIdea from './pages/BestIdea';
import Financial from './pages/Financial';
import Mindset from './pages/Mindset';
import Learning from './pages/Learning';
import Health from './pages/Health';
import Checkin from './pages/Checkin';
import Reports from './pages/Reports';
import AIAdvisor from './pages/AIAdvisor';
import Layout from './components/Layout';
import { C } from './theme';

const theme = createTheme({
  palette: {
    mode: 'light',
    primary:    { main: C.green, contrastText: C.pearl },
    secondary:  { main: C.purple, contrastText: C.pearl },
    background: { default: C.cream, paper: C.white },
    text:       { primary: C.textDark, secondary: C.textMid },
    divider:    C.cardBorder,
  },
  typography: {
    fontFamily: '"Inter", "Segoe UI", sans-serif',
    h4: { fontWeight: 800, letterSpacing: '-0.5px', color: C.purple },
    h5: { fontWeight: 700, letterSpacing: '-0.3px', color: C.purple },
    h6: { fontWeight: 700, color: C.purple },
  },
  shape: { borderRadius: 12 },
  components: {
    MuiCard: {
      styleOverrides: {
        root: {
          backgroundImage: 'none', backgroundColor: C.white,
          border: `1px solid ${C.cardBorder}`,
          boxShadow: '0 2px 12px rgba(22,23,72,0.06)',
          transition: 'box-shadow 0.2s, transform 0.2s',
          '&:hover': { boxShadow: '0 6px 24px rgba(22,23,72,0.10)' }
        }
      }
    },
    MuiPaper:    { styleOverrides: { root: { backgroundImage: 'none' } } },
    MuiButton: {
      styleOverrides: {
        root: { borderRadius: 10, textTransform: 'none', fontWeight: 700,
          transition: 'all 0.2s', '&:hover': { transform: 'translateY(-1px)' } },
        contained: { background: C.greenGrad, color: C.pearl,
          boxShadow: '0 2px 8px rgba(71,133,89,0.3)',
          '&:hover': { boxShadow: '0 4px 16px rgba(71,133,89,0.4)' } }
      }
    },
    MuiChip:   { styleOverrides: { root: { fontWeight: 600, borderRadius: 8 } } },
    MuiTextField: {
      styleOverrides: {
        root: {
          '& .MuiOutlinedInput-root': {
            borderRadius: 10, backgroundColor: C.white,
            '& fieldset': { borderColor: C.cardBorder },
            '&:hover fieldset': { borderColor: C.green },
            '&.Mui-focused fieldset': { borderColor: C.green, borderWidth: 2 },
          },
          '& .MuiInputLabel-root.Mui-focused': { color: C.green },
        }
      }
    },
    MuiAccordion: {
      styleOverrides: {
        root: { boxShadow: 'none', border: `1px solid ${C.cardBorder}`,
          borderRadius: '12px !important', backgroundColor: C.pearl,
          '&:before': { display: 'none' },
          '&.Mui-expanded': { boxShadow: '0 4px 12px rgba(22,23,72,0.08)' } }
      }
    },
    MuiLinearProgress: {
      styleOverrides: {
        root: { borderRadius: 8, backgroundColor: `rgba(71,133,89,0.1)` },
        bar:  { borderRadius: 8 }
      }
    },
    MuiTabs: {
      styleOverrides: {
        root: { borderBottom: `1px solid ${C.cardBorder}` },
        indicator: { backgroundColor: C.green, height: 3, borderRadius: 3 }
      }
    },
    MuiTab: {
      styleOverrides: {
        root: { textTransform: 'none', fontWeight: 600, color: C.greyBlue,
          '&.Mui-selected': { color: C.green } }
      }
    },
    MuiDivider:   { styleOverrides: { root: { borderColor: C.cardBorder } } },
    MuiCheckbox:  { styleOverrides: { root: { color: `rgba(71,133,89,0.3)`, '&.Mui-checked': { color: C.green } } } },
  }
});

function App() {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AuthProvider>
        <BrowserRouter>
          <Routes>
            <Route path="/" element={<Layout />}>
              <Route index element={<Dashboard />} />
              <Route path="business"  element={<Business />} />
              <Route path="best-idea" element={<BestIdea />} />
              <Route path="financial" element={<Financial />} />
              <Route path="mindset"   element={<Mindset />} />
              <Route path="learning"  element={<Learning />} />
              <Route path="health"    element={<Health />} />
              <Route path="checkin"   element={<Checkin />} />
              <Route path="reports"   element={<Reports />} />
              <Route path="ai"        element={<AIAdvisor />} />
            </Route>
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </BrowserRouter>
      </AuthProvider>
    </ThemeProvider>
  );
}

export default App;
